"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[961344],{488241(e){e.exports=JSON.parse('{"tag":{"label":"fluent","permalink":"/sdk/tags/fluent","allTagsPath":"/sdk/tags","count":9,"items":[{"id":"fluent/override-guide","title":"$override \u2014 Setting Properties Not Modeled by the API","description":"$override is an escape hatch on Fluent API constructors. Use it to set fields that the typed API does not expose \u2014 typically customer-added columns (x/u prefixed), fields added by another application, or out-of-the-box columns that simply aren\'t in the API surface yet.","permalink":"/sdk/fluent/override-guide"},{"id":"fluent/data-helpers-guide","title":"Data Helpers","description":"Fluent provides global helper functions for creating typed values in Record() data fields.","permalink":"/sdk/fluent/data-helpers-guide"},{"id":"guides/developing-apps-guide","title":"Developing ServiceNow Apps with the Now SDK","description":"Guide for ServiceNow app development using the Now SDK: project setup, fluent authoring, build/deploy workflow, and CLI reference. Start here when working on a new ServiceNow application or with the Now SDK before consulting artifact-specific guides.","permalink":"/sdk/guides/developing-apps-guide"},{"id":"fluent/now-attach-guide","title":"Now.attach","description":"Now.attach() attaches an image file to a record at build time. It reads the file, compresses it, and creates the corresponding sysattachment and sysattachment_doc records in the XML output.","permalink":"/sdk/fluent/now-attach-guide"},{"id":"fluent/now-del-guide","title":"Now.del","description":"Marks a record for deletion. When the application is deployed, records marked with Now.del() will be removed from the target instance.","permalink":"/sdk/fluent/now-del-guide"},{"id":"fluent/now-id-guide","title":"Now.ID","description":"Now.ID[\'key-name\'] gives a Fluent record a stable, human-readable identity. Use it to assign the $id property on any API that accepts one \u2014 the build system maps the key to a real sys_id and keeps it stable across builds.","permalink":"/sdk/fluent/now-id-guide"},{"id":"fluent/now-include-guide","title":"Now.include","description":"Now.include() populates a record field with the contents of a file at build time. It reads the file and inlines its text into the XML output, keeping source files separate for IDE support (syntax highlighting, IntelliSense, linting).","permalink":"/sdk/fluent/now-include-guide"},{"id":"fluent/now-ref-guide","title":"Now.ref","description":"Now.ref() creates a reference to a record in another table. Use it when a field needs to point to a record that isn\'t defined in the current file \u2014 for example, referencing a role, a flow, or any record identified by its sys_id or coalesce keys.","permalink":"/sdk/fluent/now-ref-guide"},{"id":"guides/fluent-overview","title":"ServiceNow Fluent Overview","description":"ServiceNow Fluent is a domain-specific language (DSL) based on TypeScript for defining the metadata files [sys_metadata] that make up applications. It includes APIs for tables, roles, ACLs, business rules, Automated Test Framework tests, and more.","permalink":"/sdk/guides/fluent-overview"}],"unlisted":false}}')}}]);